DOC_APPEND = "\n## MVP-008b + MVP-009 — Caméra souris et connaissance progressive\n\n### Navigation de caméra\n\nLes deux vues stratégiques possèdent désormais leur propre contexte orbital :\n\n- clic droit maintenu : rotation autour du point observé ;\n- clic molette maintenu : déplacement du point observé ;\n- molette : zoom ;\n- `WASD` et `Q/E` restent disponibles comme commandes de secours ;\n- les angles, distances et points de focus Univers/Système sont conservés lors\n  des transitions ;\n- le déplacement souris utilise le delta brut accumulé de la frame, sans être\n  multiplié par le delta temporel.\n\n### Connaissance progressive\n\nLa liste binaire des systèmes connus est remplacée par deux collections\npersistantes :\n\n```text\nsystem_knowledge: Vec<SystemKnowledge>\nplanet_knowledge: Vec<PlanetKnowledge>\n```\n\nNiveaux :\n\n```text\nUnknown -> Detected -> Probed -> Analyzed -> Colonized\n```\n\nRègles :\n\n- une connaissance ne peut jamais régresser ;\n- l'absence d'entrée équivaut à `Unknown` ;\n- `Detected` affiche seulement un signal ou une silhouette ;\n- `Probed` révèle l'identité et permet d'ouvrir un système ;\n- `Analyzed` révèle les détails exacts disponibles ;\n- `Colonized` est réservé aux objets possédant une colonie ;\n- sonder un système détecte ses planètes et ses voisins directs ;\n- les routes sont visibles lorsque leurs deux extrémités sont détectées et\n  qu'au moins l'une est sondée ;\n- le système natal et la planète mère commencent `Colonized` ;\n- les autres planètes du système natal commencent `Detected` ;\n- les voisins directs du système natal commencent `Detected`.\n\nTant que les missions de sonde ne sont pas implémentées, la touche `K` fait\nprogresser la cible sélectionnée jusqu'à `Analyzed`. Elle ne peut jamais\ncoloniser.\n\nDans la vue Système, `Tab` sélectionne successivement les planètes visibles.\nDans la vue Univers, `Tab` continue de parcourir les systèmes visibles.\n\nVersions après migration :\n\n- `GAME_STATE_VERSION = 4` ;\n- `SAVE_VERSION = 5`.\n\nLa seed, la version de génération et le fingerprint de l'univers ne changent\npas.\n"


@dataclass(frozen=True)
class Update:
    path: Path
    before: str
    after: str


def run(
    command: list[str],
    *,
    cwd: Path,
    check: bool = True,
    capture: bool = True,
) -> subprocess.CompletedProcess[str]:
    print("$", " ".join(command))
    result = subprocess.run(
        command,
        cwd=cwd,
        text=True,
        stdout=subprocess.PIPE if capture else None,
        stderr=subprocess.STDOUT if capture else None,
    )
    if capture and result.stdout:
        print(
            result.stdout,
            end="" if result.stdout.endswith("\n") else "\n",
        )
    if check and result.returncode != 0:
        raise SystemExit(
            f"Commande en échec ({result.returncode}) : "
            f"{' '.join(command)}"
        )
    return result


def find_root(start: Path) -> Path:
    for candidate in [start, *start.parents]:
        if (
            (candidate / ".git").exists()
            and (candidate / "Cargo.toml").exists()
            and (
                candidate
                / "crates/galactic_sim/src/state.rs"
            ).exists()
            and (
                candidate
                / "crates/galactic_client/src/lib.rs"
            ).exists()
        ):
            return candidate

    raise SystemExit(
        "Racine Galactic introuvable. Utilise --root."
    )


def normalize(text: str) -> str:
    return text.rstrip() + "\n"


def verify_baseline(root: Path, force: bool) -> None:
    head = run(
        ["git", "rev-parse", "HEAD"],
        cwd=root,
    ).stdout.strip()
    if head == EXPECTED_BASELINE_COMMIT:
        print(f"Baseline reconnue : {head}")
        return

    ancestor = run(
        [
            "git",
            "merge-base",
            "--is-ancestor",
            EXPECTED_BASELINE_COMMIT,
            "HEAD",
        ],
        cwd=root,
        check=False,
    )
    if ancestor.returncode == 0:
        print(
            "Baseline présente dans l'historique ; "
            f"HEAD actuel : {head}"
        )
        return
    if force:
        print(
            "WARNING: baseline différente, poursuite "
            "autorisée par --force."
        )
        return

    raise SystemExit(
        "Le dépôt local ne correspond pas à la baseline "
        "MVP-008 analysée.\n"
        f"HEAD={head}\n"
        f"Attendu={EXPECTED_BASELINE_COMMIT}\n"
        "Synchronise le dépôt ou utilise --force après "
        "vérification."
    )


